// 1. Retrieve the existing table from global context, or initialize it
let tableData = global.get("tsacVoltageTable");

if (!tableData) {
    tableData = [];
    // Initialize 22 rows with blank/null values
    for (let i = 1; i <= 22; i++) {
        tableData.push({
            "Cell": i,
            "TSAC 1": null,
            "TSAC 2": null,
            "TSAC 3": null,
            "TSAC 4": null,
            "TSAC 5": null
        });
    }
}

// 2. Process the incoming parsed data
let incomingData = msg.payload;

for (let segmentKey in incomingData) {
    if (incomingData.hasOwnProperty(segmentKey) && segmentKey.startsWith("TSAC_Voltages")) {

        // Extract the segment number (1-5) to match the column names
        let segmentNum = segmentKey.replace("TSAC_Voltages", "");
        let columnName = "TSAC segment " + segmentNum;

        let segmentData = incomingData[segmentKey];

        // Update the 22 rows for this specific column
        for (let i = 1; i <= 22; i++) {
            let voltageKey = `${segmentKey}_${i}`;

            if (segmentData.hasOwnProperty(voltageKey)) {
                let rawValue = segmentData[voltageKey];

                // Divide by 10000, force 4 decimal places, and append " V"
                let formattedVoltage = rawValue.toFixed(4) + " V";

                tableData[i - 1][columnName] = formattedVoltage;
            }
        }
    }
}

// 3. Save the updated table back to the global context
global.set("tsacVoltageTable", tableData);

// 4. Send the complete, updated table to the dashboard
msg.payload = tableData;
return msg;

let emptyTable = [];

// Rebuild the 22 empty rows
for (let i = 1; i <= 22; i++) {
    emptyTable.push({
        "Cell": i,
        "TSAC segment 1": null,
        "TSAC segment 2": null,
        "TSAC segment 3": null,
        "TSAC segment 4": null,
        "TSAC segment 5": null
    });
}

// Overwrite the saved global table with the empty one
global.set("tsacVoltageTable", emptyTable);

// Send the empty table to the dashboard to clear the view
msg.payload = emptyTable;
return msg;

let testPayload = {};

// Loop through the 5 possible TSAC segments
for (let tsac = 1; tsac <= 5; tsac++) {

    // 80% chance to include this segment in the current message 
    // (This tests your system's ability to handle partial data)
    if (Math.random() < 0.8) {
        let tsacKey = `TSAC_Voltages${tsac}`;
        testPayload[tsacKey] = {};

        // Generate 22 cell voltages for this segment
        for (let cell = 1; cell <= 22; cell++) {
            // Generate a random raw integer between 30000 and 42000
            // When divided by 10000 in your main node, this becomes 3.0 to 4.2
            let randomRawVoltage = Math.floor(Math.random() * (42000 - 30000 + 1)) + 30000;

            let voltageKey = `${tsacKey}_${cell}`;
            testPayload[tsacKey][voltageKey] = randomRawVoltage;
        }
    }
}

// If by random chance no segments were generated, force TSAC 1 to generate 
// so the payload is never completely empty
if (Object.keys(testPayload).length === 0) {
    testPayload["TSAC_Voltages1"] = {};
    for (let cell = 1; cell <= 22; cell++) {
        testPayload["TSAC_Voltages1"][`TSAC_Voltages1_${cell}`] = 35000; // 3.5000 V
    }
}

msg.payload = testPayload;
return msg;

